     * More strictly, for a segment nums[i...i+k-1] to be transformable to
     * sortedNums[i...i+k-1] by cyclic shifts, the elements must be a permutation
     * of the target sorted segment, AND the elements must be "close enough"
     * to the target order to allow sorting via rotation.
     * 
     * Since rotation allows any permutation *if* all elements are distinct, 
     * but here we only have a limited set of operations (cyclic shift),
     * the elements within a block must be capable of forming the sorted sequence
     * through rotation.
     * 
     * If all elements in a block are distinct, any permutation can be achieved
     * by cyclic shifts if k > 1 (though this is generally false, it's complex).
     * 
     * Key insight from similar problems: If a segment of length k can be
     * transformed into a target sorted segment using only cyclic shifts, 
     * the elements in the segment must be a permutation of the target segment,
     * AND there must exist a rotation that matches the target.
     * 
     * For a segment S of length k, let S_sorted be its sorted version.
     * S can be transformed into S_sorted by cyclic shifts if and only if
     * S_sorted is a cyclic shift of S.
     */
    const canSortSubarray = (arr, target) => {
        const k = arr.length;
        if (k === 1) {
            return arr[0] === target[0];
        }

        // Check if the multisets are the same (necessary condition)
        const arrCounts = new Map();
        const targetCounts = new Map();
        for (const x of arr) {
            arrCounts.set(x, (arrCounts.get(x) || 0) + 1);
        }
        for (const x of target) {
            targetCounts.set(x, (targetCounts.get(x) || 0) + 1);
        }
        if (arrCounts.size !== targetCounts.size) return false;
        for (const [key, count] of arrCounts.entries()) {
            if (targetCounts.get(key) !== count) return false;
        }

        // Check if target is a cyclic shift of arr
        // Concatenate arr with itself: arr + arr
        const doubledArr = [...arr, ...arr];

        // Convert arrays to strings or use a search algorithm
        // Since elements are numbers, we need a careful string representation or direct search.

        // If k=3, arr=[3,1,2], target=[1,2,3]
        // doubledArr = [3, 1, 2, 3, 1, 2]
        // We need to check if [1, 2, 3] is a contiguous subarray of doubledArr.

        for (let start = 0; start < k; start++) {
            let match = true;
            for (let i = 0; i < k; i++) {
                if (doubledArr[start + i] !== target[i]) {
                    match = false;
                    break;
                }
            }
            if (match) {
                return true;
            }
        }

        return false;
    };

    // Find all divisors of N
    const divisors = [];
    for (let k = 1; k * k <= n; k++) {
        if (n % k === 0) {
            divisors.push(k);
            if (k * k !== n) {
                divisors.push(n / k);
            }
        }
    }

    let sumK = 0;

    for (const k of divisors) {
        let possible = true;

        // k must divide n, which is guaranteed by the loop structure.

        // Divide nums into segments of length k
        const numSegments = n / k;

        for (let i = 0; i < numSegments; i++) {
            const start = i * k;

            // 1. Extract the segment from nums
            const currentSegment = nums.slice(start, start + k);

            // 2. Determine the target segment from sortedNums
            const targetSegment = sortedNums.slice(start, start + k);

            // 3. Check if the current segment can be transformed into the target segment
            if (!canSortSubarray(currentSegment, targetSegment)) {
                possible = false;
                break;
            }
        }

        if (possible) {
            sumK += k;
        }
    }

    return sumK;
}
